mapper.select:
SELECT COALESCE(SUM(prompt_tokens), 0) AS totalPromptTokens, COALESCE(SUM(completion_tokens), 0) AS totalCompletionTokens, COALESCE(SUM(total_tokens), 0) AS totalTokens, COALESCE(SUM(cost_amount), 0) AS totalCost, COUNT(*) AS totalRequests, COUNT(CASE WHEN success = true THEN 1 END) AS successRequests, COUNT(CASE WHEN success = false THEN 1 END) AS failedRequests, CASE WHEN COUNT(*) > 0 THEN ROUND(COUNT(CASE WHEN success = true THEN 1 END) * 100.0 / COUNT(*), 2) ELSE 0 END AS successRate, COALESCE(AVG(latency_ms), 0) AS avgLatencyMs, CASE WHEN EXTRACT(EPOCH FROM (MAX(created_at) - MIN(created_at))) > 0 THEN ROUND(COUNT(*) * 60.0 / EXTRACT(EPOCH FROM (MAX(created_at) - MIN(created_at))), 2) ELSE COUNT(*) END AS avgRpm, CASE WHEN EXTRACT(EPOCH FROM (MAX(created_at) - MIN(created_at))) > 0 THEN ROUND(SUM(total_tokens) * 60.0 / EXTRACT(EPOCH FROM (MAX(created_at) - MIN(created_at))), 2) ELSE COALESCE(SUM(total_tokens), 0) END AS avgTpm FROM llm_usage_records WHERE created_at >= #{startTime}
AND user_id = #{userId}
AND group_id = #{groupId}

SELECT TO_CHAR(created_at, 'YYYY-MM-DD') AS date, COUNT(*) AS requests, COALESCE(SUM(total_tokens), 0) AS tokens, COALESCE(SUM(cost_amount), 0) AS cost FROM llm_usage_records WHERE created_at >= #{startTime}
AND module = #{module}
GROUP BY TO_CHAR(created_at, 'YYYY-MM-DD') ORDER BY date ASC
